"use strict";(self.webpackChunkzhishi=self.webpackChunkzhishi||[]).push([[2186],{9664:(n,s,a)=>{a.r(s),a.d(s,{data:()=>p});const p={key:"v-151e25ce",path:"/fe/webpack/",title:"学习 webpack",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"webpack 的常用属性",slug:"webpack-的常用属性",children:[]},{level:2,title:"entry 入口",slug:"entry-入口",children:[]},{level:2,title:"output 输出",slug:"output-输出",children:[{level:3,title:"outpu.publicPath",slug:"outpu-publicpath",children:[]}]},{level:2,title:"Loader",slug:"loader",children:[{level:3,title:"loader 使用方式",slug:"loader-使用方式",children:[]},{level:3,title:"常用的 loader",slug:"常用的-loader",children:[]},{level:3,title:"loader 的工作流程",slug:"loader-的工作流程",children:[]},{level:3,title:"手写一个 loader",slug:"手写一个-loader",children:[]}]},{level:2,title:"plugin",slug:"plugin",children:[{level:3,title:"自动清理上次打包的结果 （CleanWebpackPlugin）",slug:"自动清理上次打包的结果-cleanwebpackplugin",children:[]},{level:3,title:"用于生成 HTML 插件 html-webpack-plugin",slug:"用于生成-html-插件-html-webpack-plugin",children:[]},{level:3,title:"用于复制文件的插件 copy-webpack-plugin",slug:"用于复制文件的插件-copy-webpack-plugin",children:[]},{level:3,title:"手写一个 插件",slug:"手写一个-插件",children:[]}]},{level:2,title:"webpack 打包流程工作原理",slug:"webpack-打包流程工作原理",children:[]},{level:2,title:"webpack 工作流程",slug:"webpack-工作流程",children:[]},{level:2,title:"打包加速的方法",slug:"打包加速的方法",children:[]},{level:2,title:"webpack 常用的插件",slug:"webpack-常用的插件",children:[]},{level:2,title:"常用的 loader",slug:"常用的-loader-1",children:[]}],filePathRelative:"fe/webpack/README.md",git:{updatedTime:1627628114e3,contributors:[{name:"tangxue",email:"11183504@qq.com",commits:2}]}}},2858:(n,s,a)=>{a.r(s),a.d(s,{default:()=>e});const p=(0,a(6252).uE)('<h1 id="学习-webpack" tabindex="-1"><a class="header-anchor" href="#学习-webpack" aria-hidden="true">#</a> 学习 webpack</h1><p>前端模块化打包工具</p><h2 id="webpack-的常用属性" tabindex="-1"><a class="header-anchor" href="#webpack-的常用属性" aria-hidden="true">#</a> webpack 的常用属性</h2><ul><li>entry：打包的入口，可以是多个</li><li>output：输出配置，只能是一个</li><li>loader：核心编译</li><li>plugin：扩展</li><li>devServer：开发服务器</li></ul><h2 id="entry-入口" tabindex="-1"><a class="header-anchor" href="#entry-入口" aria-hidden="true">#</a> entry 入口</h2><ul><li><p>文件的打包入口 可以有多个入口。</p></li><li><p>css、js 都可以作为打包入口，一般情况下是 js（main.js）</p></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// webpack.config.back.js  </span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>多个入口打包</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// webpack.config.back.js  </span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&#39;./src/file_1.js&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;./src/file_2.js&#39;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="output-输出" tabindex="-1"><a class="header-anchor" href="#output-输出" aria-hidden="true">#</a> output 输出</h2><blockquote><p>可以通过配置 output 选项，告知 webpack 如何向硬盘写入编译文件。注意，即使可以存在多个 entry 起点，但只能指定一个 output 配置。</p></blockquote><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> path <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;path&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 文件的打包入口 可以有多个入口</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>  <span class="token comment">// 注意这里的 ./ 不能省略</span>\n  <span class="token comment">// 只能存在一个 输出</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token comment">// 输出文件的名称</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;03-bundle.js&#39;</span><span class="token punctuation">,</span>\n    <span class="token comment">// 输出的文件的路径名称</span>\n    path<span class="token operator">:</span> path<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;dist&#39;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="outpu-publicpath" tabindex="-1"><a class="header-anchor" href="#outpu-publicpath" aria-hidden="true">#</a> outpu.publicPath</h3><p>配置项目的公共路径 一般是cnd路径</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 文件的打包入口 可以有多个入口</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>  <span class="token comment">// 注意这里的 ./ 不能省略</span>\n  <span class="token comment">// 只能存在一个 输出</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token comment">// 输出文件的名称</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;03-bundle.js&#39;</span><span class="token punctuation">,</span>\n    <span class="token comment">// 输出的文件的路径名称</span>\n    path<span class="token operator">:</span> path<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;dist&#39;</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token comment">// 项目的公共路径 </span>\n    publicPath<span class="token operator">:</span><span class="token string">&#39;/CDN/apps&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>也可以在入口文件中通过 <code>__webpack_public_path__</code> 动态配置 (微前端中配置过)</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>__webpack_public_path__ <span class="token operator">=</span> myRuntimePublicPath<span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="loader" tabindex="-1"><a class="header-anchor" href="#loader" aria-hidden="true">#</a> Loader</h2><blockquote><p>loader 的作用很简单，就是处理任意的文件，并将它们转换成一个 webpack 可以处理的模块</p></blockquote><ul><li>webpack 内部默认只能处理，js 模块代码，在打包过程中，它默认把所有遇到的文件当作 js 代码来解析</li><li>webpack 是使用 loader 来处理每个模块的，而内部的 loader 只能处理 js 模块，如果需要其他模块学院配置不同的 loader</li></ul><img src="img/img1.png" width="600"><h3 id="loader-使用方式" tabindex="-1"><a class="header-anchor" href="#loader-使用方式" aria-hidden="true">#</a> loader 使用方式</h3><p>在 module 中添加一个 rules 数组，这个数组就是针对资源模块的加载规则配置</p><p>每个规则中都要设置两个属性：</p><ul><li>test 属性：它是一个正则表达式，用来匹配打包过程遇到的文件路径</li><li>use 属性：它用来中的指定文件使用的 loader</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> path <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;path&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  mode<span class="token operator">:</span> <span class="token string">&#39;none&#39;</span><span class="token punctuation">,</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;03-bundle.js&#39;</span><span class="token punctuation">,</span>\n    path<span class="token operator">:</span> path<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;dist&#39;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  module<span class="token operator">:</span> <span class="token punctuation">{</span>\n    rules<span class="token operator">:</span> <span class="token punctuation">[</span>\n      <span class="token punctuation">{</span>\n        <span class="token comment">// 正则表达式，来匹配文件</span>\n        test<span class="token operator">:</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">\\.css$</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">,</span>\n        <span class="token comment">//  指定具体的 loader</span>\n        use<span class="token operator">:</span> <span class="token punctuation">[</span>\n          <span class="token string">&#39;css-loader&#39;</span>\n        <span class="token punctuation">]</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">]</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br></div></div><p>这样 css 文件就会交给 css-loader 处理后再有 webpack 打包</p><p><code>css 文件</code> ==&gt; <code>css-loader</code> ==&gt; <code>webpack</code> ==&gt; <code>bundle.js</code></p><img src="img/img3.png" width="600"><h4 id="样式加载失败" tabindex="-1"><a class="header-anchor" href="#样式加载失败" aria-hidden="true">#</a> 样式加载失败</h4><p>css-loader 只是把 css 编译成 一段 css 字符串模块，只会把css模块加载到js中，而并不会使用这个模块</p><img src="img/img2.png" width="600"><ul><li><p>使用 style-loader 把 css-loader 转换的结果通过 style 标签添加到页面上</p></li><li><p>多个 loader 的执行顺序，从后往前执行</p></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> path <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;path&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 打包模式</span>\n  mode<span class="token operator">:</span> <span class="token string">&#39;none&#39;</span><span class="token punctuation">,</span>\n  <span class="token comment">// 文件的打包入口 可以有多个入口</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>  <span class="token comment">// 注意这里的 ./ 不能省略</span>\n  <span class="token comment">// 只能存在一个 输出</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;03-bundle.js&#39;</span><span class="token punctuation">,</span>\n    <span class="token comment">// 输出的文件名称</span>\n    path<span class="token operator">:</span> path<span class="token punctuation">.</span><span class="token function">join</span><span class="token punctuation">(</span>__dirname<span class="token punctuation">,</span> <span class="token string">&#39;dist&#39;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  module<span class="token operator">:</span> <span class="token punctuation">{</span>\n    rules<span class="token operator">:</span> <span class="token punctuation">[</span>\n      <span class="token punctuation">{</span>\n        <span class="token comment">// 正则表达式，来匹配文件</span>\n        test<span class="token operator">:</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">\\.css$</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">,</span>\n        <span class="token comment">//  指定具体的 loader</span>\n        <span class="token comment">// 多个 loader 的执行顺序，从后往前执行</span>\n        use<span class="token operator">:</span> <span class="token punctuation">[</span>\n          <span class="token string">&#39;style-loader&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;css-loader&#39;</span>\n        <span class="token punctuation">]</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">]</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br></div></div><h3 id="常用的-loader" tabindex="-1"><a class="header-anchor" href="#常用的-loader" aria-hidden="true">#</a> 常用的 loader</h3><p>| 名称 | 说明 | | -------- | --- | --- | |file-loader | 将一个文件中的 import/require() 解析为 url，并且将文件发送到输出文件夹。| |url-loader | 用于将文件转换为 base64 URI 的 loader。| |babel-loader| 编译 js 文件 | |css-loader| 处理 css 文件，并对 @import 和 url() 进行处理| |style-loader| 把 CSS 插入到 DOM 中| |eslint-loader| lint 检查 | |vue-loader | 处理 .vue 文件|</p><h3 id="loader-的工作流程" tabindex="-1"><a class="header-anchor" href="#loader-的工作流程" aria-hidden="true">#</a> loader 的工作流程</h3><ul><li>loader 都需要导出一个函数</li><li>loader 接收源文件的内容字符串或者 buffer</li><li>webpack 为 loader 提供上下文，有一些 api 可以使用</li></ul><p>简单的工作流程：</p><ol><li>webpack.config.back.js 配置一个 js-loader</li><li>打包遇到 js 文件，执行 js-loader</li><li>js-loader 是一个函数，接收来文件的 source</li><li>js-loader 可以使用一些方法对 source 进行处理，得到结果 result</li><li>将 result 返回或者传递给下一个 loader ，<strong>最后结果必须是一段标准的 JS 代码字符串。</strong></li></ol><p>Webpack 加载资源文件的过程类似于一个工作管道，你可以在这个过程中依次使用多个 Loader，但是最终这个管道结束过后的结果必须是一段标准的 JS 代码字符串。</p><h3 id="手写一个-loader" tabindex="-1"><a class="header-anchor" href="#手写一个-loader" aria-hidden="true">#</a> 手写一个 loader</h3><p>开发 markdown 加载器，作用 markdown 转 html 在呈现到页面上</p><img src="img/img4.png" width="600"><ol><li>开发 markdown-loader</li></ol><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// markdown-loader.js</span>\n\n<span class="token comment">// 引入 marked 模块（node 模块）</span>\n<span class="token keyword">const</span> marked <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;marked&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span><span class="token function-variable function">exports</span> <span class="token operator">=</span> <span class="token parameter">source</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 加载到文件到模块内容</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;source:&#39;</span><span class="token punctuation">,</span> source<span class="token punctuation">)</span>\n \n  <span class="token comment">//  1. 将 markdown 转换为 html 字符串</span>\n  <span class="token keyword">const</span> html <span class="token operator">=</span> <span class="token function">marked</span><span class="token punctuation">(</span>source<span class="token punctuation">)</span>\n  \n  <span class="token comment">// 2. 将 html 字符串拼接为一段导出字符串的 JS 代码 </span>\n  <span class="token comment">// const code = `module.exports = ${JSON.stringify(html)}`</span>\n  <span class="token keyword">const</span> code <span class="token operator">=</span> <span class="token template-string"><span class="token template-punctuation string">`</span><span class="token string">export default </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">${</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>html<span class="token punctuation">)</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">`</span></span>\n\n  <span class="token keyword">return</span> code \n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>webpack 也可以通过 ES Modules 的方式导出，webppack 内部会自己转换</p><ol start="2"><li>使用</li></ol><p>在 module.rules 使用 就可以了</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// ./webpack.config.back.js</span>\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;bundle.js&#39;</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  module<span class="token operator">:</span> <span class="token punctuation">{</span>\n    rules<span class="token operator">:</span> <span class="token punctuation">[</span>\n      <span class="token punctuation">{</span>\n        test<span class="token operator">:</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">\\.md$</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">,</span>\n        use<span class="token operator">:</span> <span class="token punctuation">[</span>\n          <span class="token string">&#39;./markdown-loader&#39;</span>\n        <span class="token punctuation">]</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">]</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><ul><li>也可以多个 loader 配合使用</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// markdown-loader.js</span>\n\n<span class="token comment">// 引入 marked 模块（node 模块）</span>\n<span class="token keyword">const</span> marked <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;marked&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span><span class="token function-variable function">exports</span> <span class="token operator">=</span> <span class="token parameter">source</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 加载到文件到模块内容</span>\n  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;source:&#39;</span><span class="token punctuation">,</span> source<span class="token punctuation">)</span>\n \n  <span class="token comment">//  1. 将 markdown 转换为 html 字符串</span>\n  <span class="token keyword">const</span> html <span class="token operator">=</span> <span class="token function">marked</span><span class="token punctuation">(</span>source<span class="token punctuation">)</span>\n  \n  <span class="token comment">// 2. 返回处理后的结果</span>\n  <span class="token keyword">return</span> html\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><ul><li>引入 html-loader 处理</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// ./webpack.config.back.js</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;bundle.js&#39;</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  module<span class="token operator">:</span> <span class="token punctuation">{</span>\n    rules<span class="token operator">:</span> <span class="token punctuation">[</span>\n      <span class="token punctuation">{</span>\n        test<span class="token operator">:</span> <span class="token regex"><span class="token regex-delimiter">/</span><span class="token regex-source language-regex">\\.md$</span><span class="token regex-delimiter">/</span></span><span class="token punctuation">,</span>\n        use<span class="token operator">:</span> <span class="token punctuation">[</span>\n          <span class="token string">&#39;html-loader&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;./markdown-loader&#39;</span>\n        <span class="token punctuation">]</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">]</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br></div></div><h2 id="plugin" tabindex="-1"><a class="header-anchor" href="#plugin" aria-hidden="true">#</a> plugin</h2><ul><li>webpake 插件机制的目的是为了增强 webpack 在项目自动化构建方面的能力</li><li>loader 是负责完成项目中各种各样的资源模块加载，从而实现整体项目模块化</li><li>plugin 是解决项目除了资源模块打包以外的自动化工作，plugin 能力范围更广、用途也更多</li></ul><p>常用的插件场景：</p><ul><li>实现自动在打包之前清除 dist 目录（上次打包的结果）</li><li>自动生成应用所要的 html 文件</li><li>根据环境不同为代码注入API地址这种可能变化的部分</li><li>拷贝不需要参与打包的资源文件到输出目录</li><li>压缩 webpack 打包完后输出的文件</li><li>自动发布打包结果到服务器实现自动部署</li></ul><h3 id="自动清理上次打包的结果-cleanwebpackplugin" tabindex="-1"><a class="header-anchor" href="#自动清理上次打包的结果-cleanwebpackplugin" aria-hidden="true">#</a> 自动清理上次打包的结果 （CleanWebpackPlugin）</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> <span class="token punctuation">{</span> CleanWebpackPlugin <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;clean-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;bundle.js&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  plugins<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token keyword">new</span> <span class="token class-name">CleanWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h3 id="用于生成-html-插件-html-webpack-plugin" tabindex="-1"><a class="header-anchor" href="#用于生成-html-插件-html-webpack-plugin" aria-hidden="true">#</a> 用于生成 HTML 插件 html-webpack-plugin</h3><p>相比于之前写死 HTML 文件的方式，自动生成 HTML 的优势在于：</p><ul><li>html 也输出到 dist 目录中，上线只需要把 dist 目录发布出去就行</li><li>HTML 中的 script 标签是自动引入的，所以可以确保资源文件的路径是正常的。</li><li>可以动态生成 模版 以及模版里面 title、 meta标签的信息</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>\n<span class="token keyword">const</span> HtmlWebpackPlugin <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;html-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> <span class="token punctuation">{</span> CleanWebpackPlugin <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;clean-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;bundle.js&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  plugins<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token keyword">new</span> <span class="token class-name">CleanWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token keyword">new</span> <span class="token class-name">HtmlWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n      title<span class="token operator">:</span> <span class="token string">&#39;Webpack Plugin Sample&#39;</span><span class="token punctuation">,</span>\n      template<span class="token operator">:</span> <span class="token string">&#39;./src/index.html&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><h3 id="用于复制文件的插件-copy-webpack-plugin" tabindex="-1"><a class="header-anchor" href="#用于复制文件的插件-copy-webpack-plugin" aria-hidden="true">#</a> 用于复制文件的插件 copy-webpack-plugin</h3><p>不需要参与构建的静态文件，复制到输出目录下面</p><p>图片、icon 拷贝到 static 或者 public 下面</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// ./webpack.config.back.js</span>\n\n<span class="token keyword">const</span> HtmlWebpackPlugin <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;html-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> CopyWebpackPlugin <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;copy-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n<span class="token keyword">const</span> <span class="token punctuation">{</span> CleanWebpackPlugin <span class="token punctuation">}</span> <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;clean-webpack-plugin&#39;</span><span class="token punctuation">)</span>\n\nmodule<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  entry<span class="token operator">:</span> <span class="token string">&#39;./src/main.js&#39;</span><span class="token punctuation">,</span>\n  output<span class="token operator">:</span> <span class="token punctuation">{</span>\n    filename<span class="token operator">:</span> <span class="token string">&#39;bundle.js&#39;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  plugins<span class="token operator">:</span> <span class="token punctuation">[</span>\n    <span class="token keyword">new</span> <span class="token class-name">CleanWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token keyword">new</span> <span class="token class-name">HtmlWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n      title<span class="token operator">:</span> <span class="token string">&#39;Webpack Plugin Sample&#39;</span><span class="token punctuation">,</span>\n      template<span class="token operator">:</span> <span class="token string">&#39;./src/index.html&#39;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n    <span class="token comment">// 复制文件</span>\n    <span class="token keyword">new</span> <span class="token class-name">CopyWebpackPlugin</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n        patterns<span class="token operator">:</span> <span class="token punctuation">[</span>\n          <span class="token punctuation">{</span>\n            from<span class="token operator">:</span> <span class="token string">&#39;public&#39;</span><span class="token punctuation">,</span> to<span class="token operator">:</span> <span class="token string">&#39;public&#39;</span>\n          <span class="token punctuation">}</span><span class="token punctuation">,</span>\n        <span class="token punctuation">]</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">]</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><h3 id="手写一个-插件" tabindex="-1"><a class="header-anchor" href="#手写一个-插件" aria-hidden="true">#</a> 手写一个 插件</h3><ol><li><p>webpack 的插件机制就是我日常软件开发的钩子机制</p></li><li><p>在 webpack 整个工作过程会有很多环节，为了插件的扩展，webpack在每一个环节都提供钩子函数回调。</p></li><li><p>这样我们在开发插件时候，通过不同的节点上挂在不同任务就可以了</p></li></ol><ul><li>webpack 要求我们插件必须是一个函数，或者一个包含 apply 方法的对象。</li><li>webpack 启动的时候会调用这个函数，这个函数会接受一个 compiler 的对象参数</li><li>compiler 参数是 webpack 构建过程最核心的对象，这个对象可以使用</li></ul><ol><li>compiler 对象</li></ol><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// 手写插件</span>\n<span class="token keyword">class</span> <span class="token class-name">RemoveCommentsPlugin</span> <span class="token punctuation">{</span>\n  <span class="token function">apply</span> <span class="token punctuation">(</span><span class="token parameter">compiler</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">// compiler =&gt; 包含了我们此次构建的所有配置信息</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;RemoveCommentsPlugin 启动&#39;</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ol start="2"><li>通过 compiler 对象的 hooks 属性访问 emit 钩子，在通过tap方法注册一个钩子函数</li></ol><p>这个方法接受2个参数</p><ul><li>插件的名字</li><li>挂载到钩子上函数，函数可以接收一个 compilation 参数，这个参数是此次允许打包的上下文</li></ul><p>简单流程</p><ol><li>通过 compilation.assets 属性回去资源文件信息，它是一个对象，其中对象的 key 是每一个文件的名称</li><li>for in 遍历获取每个文件对象的 source 方法</li><li>判断是否是 js 文件，如果是 js 文件，就处理文本内容，生成新的文本内容（处理注释）</li><li>暴露一个新的 source 方法来返回新文本内容，和一个 size方法，用来返回内容的大小</li><li>最后覆盖掉 compilation.assets[key] 对应的属性，webpack 内部要求的格式</li></ol><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">class</span> <span class="token class-name">RemoveCommentsPlugin</span> <span class="token punctuation">{</span>\n  <span class="token function">apply</span> <span class="token punctuation">(</span><span class="token parameter">compiler</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    compiler<span class="token punctuation">.</span>hooks<span class="token punctuation">.</span>emit<span class="token punctuation">.</span><span class="token function">tap</span><span class="token punctuation">(</span><span class="token string">&#39;RemoveCommentsPlugin&#39;</span><span class="token punctuation">,</span> <span class="token parameter">compilation</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n      <span class="token comment">// compilation =&gt; 可以理解为此次打包的上下文</span>\n      <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> name <span class="token keyword">in</span> compilation<span class="token punctuation">.</span>assets<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token punctuation">)</span>\n      <span class="token punctuation">}</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n  <span class="token punctuation">}</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><h2 id="webpack-打包流程工作原理" tabindex="-1"><a class="header-anchor" href="#webpack-打包流程工作原理" aria-hidden="true">#</a> webpack 打包流程工作原理</h2><ol><li>Webpack CLI 启动打包流程；</li><li>载入 Webpack 核心模块，创建 Compiler（康派来儿） 对象；</li><li>使用 Compiler 对象开始编译整个项目；</li><li>从入口文件开始，解析模块依赖，形成依赖关系树；</li><li>递归依赖树，将每个模块交给对应的 Loader 处理；</li><li>合并 Loader 处理完的结果，将打包结果输出到 dist 目录。</li></ol><h2 id="webpack-工作流程" tabindex="-1"><a class="header-anchor" href="#webpack-工作流程" aria-hidden="true">#</a> webpack 工作流程</h2><ol><li>参数解析</li><li>找到入口文件</li><li>调用 Loader 编译文件</li><li>遍历 AST，收集依赖</li><li>生成 Chunk</li><li>输出文件</li></ol><h2 id="打包加速的方法" tabindex="-1"><a class="header-anchor" href="#打包加速的方法" aria-hidden="true">#</a> 打包加速的方法</h2><ul><li>多线程编译，加快编译速度：thread-loader（四软特）、happypack</li><li>第三方依赖外链 script 引入：vue、ui组件、JQuery等</li><li>Tree Shaking（谁给ing）摇树：基于es6 提供的模块系统，对代码惊喜静态分析， 并在压缩阶段将代码中死代码（dead code）移除，减少代码体积</li></ul><h2 id="webpack-常用的插件" tabindex="-1"><a class="header-anchor" href="#webpack-常用的插件" aria-hidden="true">#</a> webpack 常用的插件</h2><ul><li>TerserPlugin（特si）（老版本用UglifyJsPlugin）：压缩代码，删除 log 日志</li><li>CopyWebpackPlugin：复制文件，dist 目录下 复制到 /nginx/dist/ 目录</li><li>webpack-bundle-analyzer（ban dou）（安的来ze儿）：webpack打包出来的各个文件体积大小，以便我们定位大文件，进行体积优化</li><li>DefinePlugin：定义全局变量。项目环境下 修改 process.env，添加项目ID</li><li>HotModuleReplacementPlugin：页面热更新插件</li></ul><h2 id="常用的-loader-1" tabindex="-1"><a class="header-anchor" href="#常用的-loader-1" aria-hidden="true">#</a> 常用的 loader</h2><ul><li>babel-loader：转换es6语法，打补丁</li><li>style-loader：将所有的计算后的样式加入页面中，二者组合在一起使你能够把样式表嵌入webpack打包后的js文件中</li><li>css-loader：加载 import 进来的css</li></ul>',89),e={render:function(n,s){return p}}}}]);